export class NewsPage{constructor(){this.data=[],this.init()}async init(){this.data=await this.getData(),this.showNews()}async getData(){const t=await fetch("../../data/news.json");return await t.json()}showNews(){const t=document.getElementById("news-items");this.data.forEach(e=>{const a=document.createElement("div");a.classList.add("item");const s=document.createElement("div");s.classList.add("date"),s.innerText=e.date;const n=document.createElement("div");n.classList.add("messages"),e.messages.forEach(t=>{const e=document.createElement("div");e.classList.add("message");const a=document.createElement("div");a.classList.add("important-circle"),a.innerText="!";const s=document.createElement("div");s.classList.add("time"),s.innerText=t.time+":";const d=document.createElement("div");d.classList.add("text"),d.innerText=t.text,!0===t.important&&e.classList.add("important"),e.appendChild(s),e.appendChild(d),e.appendChild(a),n.append(e)}),a.appendChild(s),a.appendChild(n),t.appendChild(a)})}}